diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..ced55bb0bf3f 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -638,6 +638,14 @@ static Decomposition decompose(Value *V,
     ResA.sub(ResB);
     return ResA;
   }
+  if (match(V, m_Intrinsic<Intrinsic::usub_sat>(m_Value(Op0), m_Value(Op1)))) {
+    auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
+    auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
+    ResA.sub(ResB);
+    // x - y >= 0 -> x >= y
+    Preconditions.emplace_back(CmpInst::ICMP_UGE, Op0, Op1);
+    return ResA;
+  }

   return {V, IsKnownNonNegative};
 }
@@ -1120,10 +1128,11 @@ void State::addInfoFor(BasicBlock &BB) {
       }
       break;
     }
-    // Enqueue ssub_with_overflow for simplification.
-    case Intrinsic::ssub_with_overflow:
     case Intrinsic::ucmp:
     case Intrinsic::scmp:
+    case Intrinsic::usub_sat:
+      WorkList.push_back(
+          FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
       WorkList.push_back(
           FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
       break;
@@ -1719,11 +1728,21 @@ tryToSimplifyOverflowMath(IntrinsicInst *II, ConstraintInfo &Info,
   };

   bool Changed = false;
-  if (II->getIntrinsicID() == Intrinsic::ssub_with_overflow) {
-    // If A s>= B && B s>= 0, ssub.with.overflow(a, b) should not overflow and
-    // can be simplified to a regular sub.
+    if (!DoesConditionHold(CmpInst::ICMP_SGE, A, B, Info) ||
+        !DoesConditionHold(CmpInst::ICMP_SGE, B,
+                           ConstantInt::get(A->getType(), 0), Info))
+      return false;
+    Changed = replaceSubOverflowUses(II, A, B, ToRemove);
+  } else if (II->getIntrinsicID() == Intrinsic::usub_sat) {
     Value *A = II->getArgOperand(0);
     Value *B = II->getArgOperand(1);
+    if (DoesConditionHold(CmpInst::ICMP_UGE, A, B, Info)) {
+      IRBuilder<> Builder(II);
+      Value *Sub = Builder.CreateSub(A, B, "", /*HasNUW=*/true, /*HasNSW=*/false);
+      II->replaceAllUsesWith(Sub);
+      ToRemove.push_back(II);
+      Changed = true;
+    }
     if (!DoesConditionHold(CmpInst::ICMP_SGE, A, B, Info) ||
         !DoesConditionHold(CmpInst::ICMP_SGE, B,
                            ConstantInt::get(A->getType(), 0), Info))

