   449 | static Decomposition decomposeGEP(GEPOperator &GEP,
   450 |                                   SmallVectorImpl<ConditionTy> &Preconditions,
   451 |                                   bool IsSigned, const DataLayout &DL) {
   452 |   // Do not reason about pointers where the index size is larger than 64 bits,
   453 |   // as the coefficients used to encode constraints are 64 bit integers.
   454 |   if (DL.getIndexTypeSizeInBits(GEP.getPointerOperand()->getType()) > 64)
   455 |     return &GEP;
   456 | 
   457 |   assert(!IsSigned && "The logic below only supports decomposition for "
   458 |                       "unsigned predicates at the moment.");
   459 |   const auto &[BasePtr, ConstantOffset, VariableOffsets, NW] =
   460 |       collectOffsets(GEP, DL);
   461 |   // We support either plain gep nuw, or gep nusw with non-negative offset,
   462 |   // which implies gep nuw.
   463 |   if (!BasePtr || NW == GEPNoWrapFlags::none())
   464 |     return &GEP;
   465 | 
   466 |   Decomposition Result(ConstantOffset.getSExtValue(), DecompEntry(1, BasePtr));
   467 |   for (auto [Index, Scale] : VariableOffsets) {
   468 |     auto IdxResult = decompose(Index, Preconditions, IsSigned, DL);
   469 |     IdxResult.mul(Scale.getSExtValue());
   470 |     Result.add(IdxResult);
   471 | 
